	dp := make([][]int64, len(nums)+1)
	for i := range dp {
		dp[i] = make([]int64, k+1)
	}
	// Base case: if there is only one group, the maximum XOR is the XOR of the entire array
	for i := 1; i <= len(nums); i++ {
		dp[i][1] = prefixXOR[i] ^ prefixXOR[0]
	}

	// Fill the DP table
	for j := 2; j <= k; j++ {
		for i := j; i <= len(nums); i++ {
			// Try all possible positions to split the array
			for m := j - 1; m < i; m++ {
				// The maximum XOR for the first m elements divided into j-1 groups
				// and the XOR of the last part (from m to i-1)
				currentMax := math.MaxFloat64
				currentMax = math.Max(currentMax, dp[m][j-1])
				currentMax = math.Max(currentMax, prefixXOR[i]^prefixXOR[m])
				dp[i][j] = math.Min(dp[i][j], currentMax)
			}
		}
	}

	return dp[len(nums)][k]
